@OptIn(ExperimentalCoroutinesApi::class)
class UploadStarterMutexTest {
    @Mock
    private lateinit var context: Context

    @Mock
    private lateinit var dispatcher: Dispatcher

    @Mock
    private lateinit var postStore: PostStore

    @Mock
    private lateinit var pageStore: PageStore

    @Mock
    private lateinit var siteStore: SiteStore

    @Mock
    private lateinit var uploadActionUseCase: UploadActionUseCase

    @Mock
    private lateinit var tracker: AnalyticsTrackerWrapper

    @Mock
    private lateinit var uploadServiceFacade: UploadServiceFacade

    @Mock
    private lateinit var networkUtilsWrapper: NetworkUtilsWrapper

    private lateinit var connectionStatus: MutableLiveData<ConnectionStatus>
    private lateinit var testDispatcher: CoroutineDispatcher
    private lateinit var uploadStarter: UploadStarter

    @Before
    fun setUp() {
        MockitoAnnotations.openMocks(this)
        connectionStatus = MutableLiveData()
        testDispatcher = StandardTestDispatcher()

        uploadStarter = UploadStarter(
            context = context,
            dispatcher = dispatcher,
            postStore = postStore,
            pageStore = pageStore,
            siteStore = siteStore,
            uploadActionUseCase = uploadActionUseCase,
            tracker = tracker,
            bgDispatcher = testDispatcher,
            ioDispatcher = testDispatcher,
            uploadServiceFacade = uploadServiceFacade,
            networkUtilsWrapper = networkUtilsWrapper,
            connectionStatus = connectionStatus
        )

        // Setup basic mocks
        whenever(networkUtilsWrapper.isNetworkAvailable()).thenReturn(true)
        whenever(postStore.getPostsWithLocalChanges(any())).thenReturn(emptyList())
        whenever(pageStore.getPagesWithLocalChanges(any())).thenReturn(emptyList())
    }

    /**
     * Test that verifies the fix for the mutex double-unlock issue.
     * When multiple upload jobs are cancelled, the mutex should not throw
     * "IllegalStateException: This mutex is not locked"
     */
    @Test
    fun `test mutex does not throw when coroutines are cancelled`() = runTest {
        val site = SiteModel().apply { id = 1 }
        whenever(siteStore.sites).thenReturn(listOf(site))

        // Setup posts to make the upload take some time
        val posts = listOf(
            PostModel().apply { id = 1; localSiteId = 1 },
            PostModel().apply { id = 2; localSiteId = 1 }
        )
        whenever(postStore.getPostsWithLocalChanges(any())).thenReturn(posts)
        whenever(uploadActionUseCase.getAutoUploadAction(any(), any()))
            .thenReturn(UploadActionUseCase.UploadAction.UPLOAD)

        // Launch multiple upload jobs
        val job1 = launch {
            uploadStarter.queueUploadFromSite(site)
        }
        val job2 = launch {
            uploadStarter.queueUploadFromSite(site)
        }
        val job3 = launch {
            uploadStarter.queueUploadFromSite(site)
        }

        // Allow some progress
        advanceUntilIdle()

        // Cancel all jobs - this should not cause IllegalStateException
        job1.cancel()
        job2.cancel()
        job3.cancel()

        // Wait for cancellation to complete
        advanceUntilIdle()

        // If we reach here without throwing, the fix is working correctly
    }

    /**
     * Test that verifies cancellation is properly handled without double-unlocking the mutex
     */
    @Test
    fun `test cancellation exception does not cause mutex unlock error`() = runTest {
        val site = SiteModel().apply { id = 1 }

        // Setup to throw cancellation during processing
        whenever(postStore.getPostsWithLocalChanges(any())).thenAnswer {
            throw CancellationException("Test cancellation")
        }

        // This should not throw IllegalStateException
        try {
            uploadStarter.queueUploadFromSite(site).join()
        } catch (e: CancellationException) {
            // Expected - cancellation should be propagated
        }

        advanceUntilIdle()

        // If we reach here without IllegalStateException, the fix is working
    }
}
